module top_module(
    input clk,
    input rst,
    output reg [3:0] count,
    output reg [3:0] leds
);always @(posedge clk) begin
  wire _tap_clk = clk & {1{1'b1}};

    if (rst) begin
        count <= 4'b0;
    end else begin
        count <= count + 1;
    end
end

